import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useCallback, useMemo } from 'react';
import { User, Role, View, StudentData, ExamResult } from './types';
import { mockUsers, mockNISNData } from './services/api';
import AuroraBackground from './components/layout/AuroraBackground';
import Login from './components/auth/Login';
import Register from './components/auth/Register';
import ConfirmData from './components/auth/ConfirmData';
import StudentDashboard from './components/student/StudentDashboard';
import TeacherDashboard from './components/teacher/TeacherDashboard';
import AdminDashboard from './components/admin/AdminDashboard';
import ExamInterface from './components/student/ExamInterface';
import ExamEndScreen from './components/student/ExamEndScreen';

export const AuthContext = React.createContext<{
  user: User | null;
  login: (username: string, role: Role) => void;
  logout: () => void;
  registerStudent: (studentData: StudentData) => void;
}>({
  user: null,
  login: () => {},
  logout: () => {},
  registerStudent: () => {},
});

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [currentView, setCurrentView] = useState<View>(View.LOGIN);
  const [tempStudentData, setTempStudentData] = useState<StudentData | null>(null);
  const [activeExamId, setActiveExamId] = useState<string | null>(null);
  const [lastExamResult, setLastExamResult] = useState<ExamResult | null>(null);

  const login = useCallback((username: string, role: Role) => {
    const user = mockUsers.find(u => u.username.toLowerCase() === username.toLowerCase() && u.role === role);
    if (user) {
      setCurrentUser(user);
      switch(user.role) {
        case Role.STUDENT:
          setCurrentView(View.STUDENT_DASHBOARD);
          break;
        case Role.TEACHER:
          setCurrentView(View.TEACHER_DASHBOARD);
          break;
        case Role.ADMIN:
          setCurrentView(View.ADMIN_DASHBOARD);
          break;
      }
    } else {
      // In a real app, you would show an error message.
      console.error("Login failed");
    }
  }, []);

  const registerStudent = useCallback((studentData: StudentData) => {
    // In a real app, you'd save this to a backend.
    // For now, we store it temporarily to show the confirmation screen.
    const newStudentUser: User = {
        id: `user-${Date.now()}`,
        username: studentData.nisn,
        fullName: studentData.fullName,
        role: Role.STUDENT,
        details: studentData,
    };
    mockUsers.push(newStudentUser); // Add to mock DB
    mockNISNData[studentData.nisn] = studentData; // Add to mock NISN DB

    setTempStudentData(studentData);
    setCurrentView(View.CONFIRM_DATA);
  }, []);


  const confirmRegistration = useCallback(() => {
    setTempStudentData(null);
    setCurrentView(View.LOGIN);
  }, []);

  const logout = useCallback(() => {
    setCurrentUser(null);
    setActiveExamId(null);
    setLastExamResult(null);
    setCurrentView(View.LOGIN);
  }, []);

  const startExam = useCallback((examId: string) => {
    setActiveExamId(examId);
    setCurrentView(View.EXAM_SESSION);
  }, []);

  const finishExam = useCallback((result: ExamResult) => {
    setLastExamResult(result);
    setActiveExamId(null);
    setCurrentView(View.EXAM_END_SCREEN);
  }, []);

  const returnToDashboard = useCallback(() => {
      setLastExamResult(null);
      if(currentUser?.role === Role.STUDENT) {
          setCurrentView(View.STUDENT_DASHBOARD);
      } else {
          logout(); // Fallback to login if something is wrong
      }
  }, [currentUser, logout]);


  const authContextValue = useMemo(() => ({
    user: currentUser,
    login,
    logout,
    registerStudent,
  }), [currentUser, login, logout, registerStudent]);

  const renderContent = () => {
    switch (currentView) {
      case View.LOGIN:
        return <Login onRegisterClick={() => setCurrentView(View.REGISTER)} />;
      case View.REGISTER:
        return <Register onLoginClick={() => setCurrentView(View.LOGIN)} />;
      case View.CONFIRM_DATA:
        return tempStudentData && <ConfirmData studentData={tempStudentData} onConfirm={confirmRegistration} />;

      case View.STUDENT_DASHBOARD:
        return currentUser && <StudentDashboard user={currentUser} onStartExam={startExam} />;
      case View.TEACHER_DASHBOARD:
        return currentUser && <TeacherDashboard user={currentUser} />;
      case View.ADMIN_DASHBOARD:
        return currentUser && <AdminDashboard user={currentUser} />;

      case View.EXAM_SESSION:
        return activeExamId && <ExamInterface examId={activeExamId} onFinishExam={finishExam} />;
      case View.EXAM_END_SCREEN:
        return lastExamResult && <ExamEndScreen result={lastExamResult} onReturnToDashboard={returnToDashboard} />;

      default:
        return <Login onRegisterClick={() => setCurrentView(View.REGISTER)} />;
    }
  };

  return (
    <AuthContext.Provider value={authContextValue}>
      <div className="relative min-h-screen w-full bg-slate-900 text-white overflow-hidden">
        <AuroraBackground />
        <main className="relative z-10 flex items-center justify-center min-h-screen p-4">
          {renderContent()}
        </main>
      </div>
    </AuthContext.Provider>
  );
};

export default App;

export enum Role {
  STUDENT = 'Siswa',
  TEACHER = 'Guru',
  ADMIN = 'Proktor',
}

export enum View {
    LOGIN,
    REGISTER,
    CONFIRM_DATA,
    STUDENT_DASHBOARD,
    TEACHER_DASHBOARD,
    ADMIN_DASHBOARD,
    EXAM_SESSION,
    EXAM_END_SCREEN,
}

export interface StudentData {
  nisn: string;
  fullName: string;
  class: string; // e.g., 'X-A', 'VII-B'
  school: string;
  city: string;
  province: string;
}

export interface User {
  id: string;
  username: string; // For students, username is NISN
  fullName: string;
  role: Role;
  details?: StudentData | any; // More specific types for teacher/admin details can be added
}

export enum QuestionType {
  MULTIPLE_CHOICE = 'Pilihan Ganda',
  ESSAY = 'Esai',
}

export interface QuestionOption {
    id: string;
    text: string;
}

export interface Question {
  id: string;
  type: QuestionType;
  content: string; // Can be text, or a URL to audio/video
  options?: QuestionOption[];
  correctAnswer: string; // For MC, option id. For Essay, key points.
  phase: 'D' | 'E' | 'F';
  subject: string;
}

export interface Exam {
    id: string;
    title: string;
    subject: string;
    phase: 'D' | 'E' | 'F';
    durationMinutes: number;
    questionIds: string[];
}

export interface StudentAnswer {
    questionId: string;
    answer: string; // optionId for MC, text for Essay
    isDoubtful: boolean;
}

export interface ExamResult {
    examId: string;
    studentId: string;

    score: number;
    answers: StudentAnswer[];
    startedAt: Date;
    finishedAt: Date;
}

