interface LoginProps {
    onRegisterClick: () => void;
}

const Login: React.FC<LoginProps> = ({ onRegisterClick }) => {
  const [username, setUsername] = useState('');
  const [selectedRole, setSelectedRole] = useState<Role>(Role.STUDENT);
  const { login } = useContext(AuthContext);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (username.trim()) {
      login(username, selectedRole);
    }
  };

  return (
    <div className="w-full max-w-md bg-slate-800/40 backdrop-blur-xl p-8 rounded-2xl shadow-2xl border border-slate-700/50">
      <h1 className="text-3xl font-bold text-center text-white mb-2">Selamat Datang</h1>
      <p className="text-center text-slate-300 mb-8">Silakan masuk untuk melanjutkan</p>

      <form onSubmit={handleSubmit} className="space-y-6">
        <Input 
          id="username"
          label="NISN / Username"
          value={username}
          onChange={(e) => setUsername(e.target.value)}
          placeholder="Masukkan NISN atau username Anda"
          required
        />
        <div>
            <label className="block text-sm font-medium text-slate-300 mb-2">Masuk sebagai</label>
            <div className="grid grid-cols-3 gap-2">
                {(Object.values(Role) as Role[]).map(role => (
                    <button
                        key={role}
                        type="button"
                        onClick={() => setSelectedRole(role)}
                        className={`px-4 py-2 text-sm font-semibold rounded-lg transition ${selectedRole === role ? 'bg-indigo-600 text-white shadow-lg' : 'bg-slate-700/50 hover:bg-slate-700 text-slate-300'}`}
                    >
                        {role}
                    </button>
                ))}
            </div>
        </div>
        <Button type="submit" className="w-full">
          Masuk
        </Button>
      </form>

      <p className="text-center text-sm text-slate-400 mt-8">
        Belum punya akun?{' '}
        <button onClick={onRegisterClick} className="font-semibold text-indigo-400 hover:text-indigo-300">
          Daftar di sini
        </button>
      </p>
    </div>
  );
};

export default Login;

