interface StudentDashboardProps {
  user: User;
  onStartExam: (examId: string) => void;
  logout: () => void;
}

const StudentDashboard: React.FC<StudentDashboardProps> = ({ user, onStartExam, logout }) => {
  const [token, setToken] = useState('');

  const studentClass = user.details?.class || '';
  const gradeLevel = parseInt(studentClass.match(/\d+/)?.[0] || '0');

  const availableExams = useMemo(() => {
    const studentPhase = gradeLevel >= 10 ? 'F' : 'D'; // Simplified logic
    return mockExams.filter(exam => exam.phase === studentPhase);
  }, [gradeLevel]);

  const handleStartExam = () => {
      // In a real app, the token would be validated on the backend to find the correct examId.
      // Here, we'll just check if the token matches any of the mock exam IDs for demonstration.
      const exam = mockExams.find(e => e.id === token);
      if (exam) {
        onStartExam(exam.id);
      } else {
        alert("Token ujian tidak valid.");
      }
  };

  const handleCopyToken = (examId: string) => {
    navigator.clipboard.writeText(examId).then(() => {
      alert(`Token "${examId}" berhasil disalin!`);
    });
  }

  return (
    <div className="w-full max-w-4xl bg-white/20 backdrop-blur-2xl p-8 rounded-2xl shadow-lg border border-white/30">
      <div className="flex justify-between items-start">
        <div>
          <h1 className="text-3xl font-bold text-slate-800">Halo, {user.fullName}!</h1>
          <p className="text-slate-600 mt-1">Selamat datang di portal ujian online.</p>
        </div>
        <Button onClick={logout} variant="secondary">
          Keluar
        </Button>
      </div>

      <div className="mt-8 p-6 bg-white/30 rounded-lg">
          <h2 className="text-xl font-semibold mb-4">Mulai Ujian</h2>
          <p className="text-slate-700 mb-4">Masukkan kode token yang diberikan oleh proktor atau guru Anda untuk memulai ujian.</p>
          <div className="flex flex-col sm:flex-row items-end sm:items-center gap-4">
              <Input
                id="token"
                label="Kode Token Ujian"
                value={token}
                onChange={(e) => setToken(e.target.value)}
                placeholder="Masukkan token..."
                className="flex-grow"
              />
              <Button onClick={handleStartExam} className="w-full sm:w-auto h-12">Mulai Ujian</Button>
          </div>
      </div>

