import React, { useState } from 'react';
import * as XLSX from 'xlsx';
import mammoth from 'mammoth';
import { Question, QuestionType, QuestionOption } from '../../types';
import { addQuestions, mockQuestions } from '../../services/api';
import Button from '../ui/Button';
import Spinner from '../ui/Spinner';

const QuestionBank: React.FC = () => {
    const [selectedFile, setSelectedFile] = useState<File | null>(null);
    const [isParsing, setIsParsing] = useState(false);
    const [message, setMessage] = useState<{ type: 'success' | 'error', text: string } | null>(null);
    const [questions, setQuestions] = useState<Question[]>(mockQuestions);

    const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
        if (event.target.files) {
            setSelectedFile(event.target.files[0]);
            setMessage(null);
        }
    };

    const handleImport = async () => {
        if (!selectedFile) {
            setMessage({ type: 'error', text: 'Silakan pilih file terlebih dahulu.' });
            return;
        }
        setIsParsing(true);
        setMessage(null);

        try {
            let newQuestions: Question[] = [];
            if (selectedFile.name.endsWith('.xlsx')) {
                newQuestions = await parseXLSX(selectedFile);
            } else if (selectedFile.name.endsWith('.docx')) {
                newQuestions = await parseDOCX(selectedFile);
            } else {
                throw new Error('Format file tidak didukung. Gunakan .xlsx atau .docx');
            }

            if (newQuestions.length > 0) {
                await addQuestions(newQuestions);
                setQuestions(prev => [...prev, ...newQuestions]); // Update local state to re-render list
                setMessage({ type: 'success', text: `${newQuestions.length} soal berhasil diimpor!` });
            } else {
                setMessage({ type: 'error', text: 'Tidak ada soal yang dapat diimpor dari file. Periksa format file Anda.' });
            }
        } catch (error: any) {
            setMessage({ type: 'error', text: `Gagal mengimpor: ${error.message}` });
            console.error(error);
        } finally {
            setIsParsing(false);
            setSelectedFile(null);
        }
    };

    const parseXLSX = (file: File): Promise<Question[]> => {
        return new Promise((resolve, reject) => {
            const reader = new FileReader();
            reader.onload = (e) => {
                try {
                    const data = new Uint8Array(e.target?.result as ArrayBuffer);
                    const workbook = XLSX.read(data, { type: 'array' });
                    const sheetName = workbook.SheetNames[0];
                    const worksheet = workbook.Sheets[sheetName];
                    const json = XLSX.utils.sheet_to_json(worksheet) as any[];

                    const parsedQuestions: Question[] = json.map((row, index) => {
                        // Basic validation
                        if (!row['content'] || !row['type'] || !row['subject'] || !row['phase'] || !row['correctAnswer']) {
                            throw new Error(`Data tidak lengkap pada baris ${index + 2}`);
                        }

                        const question: Question = {
                            id: `imported-${Date.now()}-${index}`,
                            content: row['content'],
                            type: row['type'] === 'Pilihan Ganda' ? QuestionType.MULTIPLE_CHOICE : QuestionType.ESSAY,
                            subject: row['subject'],
                            phase: row['phase'],
                            correctAnswer: row['correctAnswer'].toString(),
                            options: [],
                        };

                        if (question.type === QuestionType.MULTIPLE_CHOICE) {
                            question.options = ['A', 'B', 'C', 'D', 'E']
                                .map((opt, i) => ({
                                    id: `${question.id}-o${i + 1}`,
                                    text: row[`option${opt}`],
                                }))
                                .filter(opt => opt.text); // Only add options that exist

                            // Map correct answer letter to option ID
                            const correctOptionIndex = ['A', 'B', 'C', 'D', 'E'].indexOf(row['correctAnswer'].toUpperCase());
                            if (correctOptionIndex !== -1 && question.options[correctOptionIndex]) {
                                question.correctAnswer = question.options[correctOptionIndex].id;
                            } else {
                                throw new Error(`Kunci jawaban tidak valid pada baris ${index + 2}`);
                            }
                        }
                        return question;
                    });
                    resolve(parsedQuestions);
                } catch (err) {
                    reject(err);
                }
            };
            reader.onerror = reject;
            reader.readAsArrayBuffer(file);
        });
    };

    const parseDOCX = (file: File): Promise<Question[]> => {
         return new Promise((resolve, reject) => {
            const reader = new FileReader();
            reader.onload = async (e) => {
                 try {
                    const arrayBuffer = e.target?.result as ArrayBuffer;
                    const { value: text } = await mammoth.extractRawText({ arrayBuffer });

                    // Simple parsing logic based on a defined format
                    const questionsText = text.split(/(?=\d+\.\s)/).filter(Boolean);
                    const parsedQuestions: Question[] = questionsText.map((qText, index) => {
                        const contentMatch = qText.match(/^\d+\.\s([\s\S]*?)(?=\n[A-E]\.|\nKUNCI:)/);
                        const content = contentMatch ? contentMatch[1].trim() : '';

                        const optionsMatches = [...qText.matchAll(/([A-E])\.\s(.*?)(?=\n[A-E]\.|\nKUNCI:|$)/gs)];
                        const options: QuestionOption[] = optionsMatches.map((match, i) => ({
                            id: `imported-${Date.now()}-${index}-o${i + 1}`,
                            text: match[2].trim(),
                        }));

                        const correctAnswerMatch = qText.match(/KUNCI:\s*([A-E])/i);
                        const correctLetter = correctAnswerMatch ? correctAnswerMatch[1].toUpperCase() : '';

                        const type = options.length > 0 ? QuestionType.MULTIPLE_CHOICE : QuestionType.ESSAY;

                        // Extract metadata
                        const subjectMatch = qText.match(/\[SUBJEK:\s*(.*?)\]/i);
                        const phaseMatch = qText.match(/\[FASE:\s*(.*?)\]/i);

                        if (!content || !subjectMatch || !phaseMatch) throw new Error(`Format soal no. ${index + 1} tidak lengkap (konten, subjek, atau fase tidak ditemukan).`);

                        let correctAnswer = '';
                        if (type === QuestionType.MULTIPLE_CHOICE) {
                             const correctIndex = ['A', 'B', 'C', 'D', 'E'].indexOf(correctLetter);
                             if (correctIndex !== -1 && options[correctIndex]) {
                                 correctAnswer = options[correctIndex].id;
                             } else {
                                throw new Error(`Kunci jawaban tidak valid untuk soal no. ${index + 1}`);
                             }
                        } else {
                             const essayAnswerMatch = qText.match(/KUNCI:\s*([\s\S]*?)(?=\n\[|$)/i);
                             correctAnswer = essayAnswerMatch ? essayAnswerMatch[1].trim() : '';
                        }

                        return {
                            id: `imported-${Date.now()}-${index}`,
                            content,
                            options: type === QuestionType.MULTIPLE_CHOICE ? options : undefined,
                            type,
                            correctAnswer,
                            subject: subjectMatch[1].trim(),
                            phase: phaseMatch[1].trim() as 'D' | 'E' | 'F',
                        };
                    });

                    resolve(parsedQuestions);
                } catch (err) {
                    reject(err);
                }
            };
            reader.onerror = reject;
            reader.readAsArrayBuffer(file);
        });
    };

    return (
        <div>
            <h2 className="text-2xl font-bold text-slate-800 mb-6">Bank Soal</h2>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-8 mb-8">
                <div className="bg-white/30 p-6 rounded-lg">
                    <h3 className="text-xl font-semibold text-slate-800 mb-4">Impor Soal Baru</h3>
                    <p className="text-slate-600 mb-4 text-sm">Unggah file .docx atau .xlsx untuk menambahkan soal secara massal.</p>

                    <input 
                        type="file" 
                        onChange={handleFileChange} 
                        accept=".docx,.xlsx"
                        className="block w-full text-sm text-slate-500 file:mr-4 file:py-2 file:px-4 file:rounded-full file:border-0 file:text-sm file:font-semibold file:bg-indigo-50 file:text-indigo-700 hover:file:bg-indigo-100"
                    />

                    {selectedFile && <p className="text-sm text-slate-600 mt-2">File dipilih: <strong>{selectedFile.name}</strong></p>}

                    <Button onClick={handleImport} disabled={isParsing || !selectedFile} className="mt-4 w-full">
                        {isParsing ? <Spinner /> : 'Impor Sekarang'}
                    </Button>

                    {message && (
                        <p className={`mt-4 text-sm font-medium p-3 rounded-lg ${message.type === 'success' ? 'bg-emerald-100 text-emerald-800' : 'bg-red-100 text-red-800'}`}>
                            {message.text}
                        </p>
                    )}
                </div>
                 <div className="bg-white/30 p-6 rounded-lg text-sm text-slate-700">
                    <h3 className="text-xl font-semibold text-slate-800 mb-4">Petunjuk Format</h3>
                    <div className="prose prose-sm max-w-none">
                        <p><strong>Format Excel (.xlsx):</strong></p>
                        <ul>
                            <li>Buat header: <code>content</code>, <code>type</code>, <code>subject</code>, <code>phase</code>, <code>optionA</code>, <code>optionB</code>, ..., <code>optionE</code>, <code>correctAnswer</code>.</li>
                            <li>Isi <code>type</code> dengan "Pilihan Ganda" atau "Esai".</li>
                            <li>Isi <code>correctAnswer</code> dengan huruf kunci (A-E) untuk PG atau teks jawaban untuk Esai.</li>
                        </ul>
                         <p><strong>Format Word (.docx):</strong></p>
                        <ul>
                             <li>Mulai tiap soal dengan nomor (<code>1.</code>, <code>2.</code>, dst.).</li>
                             <li>Tulis opsi dengan huruf (<code>A.</code>, <code>B.</code>, dst.) di baris baru.</li>
                             <li>Tulis kunci jawaban di baris baru dengan format: <code>KUNCI: B</code> (untuk PG) atau <code>KUNCI: Teks jawaban...</code> (untuk Esai).</li>
                             <li>Sertakan metadata di akhir soal: <code>[SUBJEK: Fisika]</code> <code>[FASE: F]</code>.</li>
                        </ul>
                    </div>
                </div>
            </div>

            <div>
                <h3 className="text-xl font-semibold text-slate-800 mb-4">Daftar Soal Saat Ini ({questions.length})</h3>
                <div className="max-h-96 overflow-y-auto bg-white/30 p-4 rounded-lg">
                    <ul className="space-y-3">
                        {questions.map((q, index) => (
                            <li key={q.id} className="p-3 bg-white/50 rounded-md text-sm">
                                <strong className="text-indigo-700">{index + 1}. ({q.subject} - {q.phase})</strong> {q.content}
                            </li>
                        ))}
                    </ul>
                </div>
            </div>
        </div>
    );
};

export default QuestionBank;

import React, { useState, useCallback, useMemo } from 'react';
import { User, Role, View, StudentData, ExamResult } from './types';
import { mockUsers, mockNISNData } from './services/api';
import AuroraBackground from './components/layout/AuroraBackground';
import Login from './components/auth/Login';
import Register from './components/auth/Register';
import ConfirmData from './components/auth/ConfirmData';
import StudentDashboard from './components/student/StudentDashboard';
import TeacherDashboard from './components/teacher/TeacherDashboard';
import AdminDashboard from './components/admin/AdminDashboard';
import ExamInterface from './components/student/ExamInterface';
import ExamEndScreen from './components/student/ExamEndScreen';
import ThemeToggle from './components/ui/ThemeToggle';

export const AuthContext = React.createContext<{
  user: User | null;
  login: (username: string, role: Role) => void;
  logout: () => void;
  registerStudent: (studentData: StudentData) => void;
}>({
  user: null,
  login: () => {},
  logout: () => {},
  registerStudent: () => {},
});

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [currentView, setCurrentView] = useState<View>(View.LOGIN);
  const [tempStudentData, setTempStudentData] = useState<StudentData | null>(null);
  const [activeExamId, setActiveExamId] = useState<string | null>(null);
  const [lastExamResult, setLastExamResult] = useState<ExamResult | null>(null);
  const [isDarkMode, setIsDarkMode] = useState(false);

  const toggleTheme = useCallback(() => {
    setIsDarkMode(prev => !prev);
  }, []);

  const login = useCallback((username: string, role: Role) => {
    const user = mockUsers.find(u => u.username.toLowerCase() === username.toLowerCase() && u.role === role);
    if (user) {
      setCurrentUser(user);
      switch(user.role) {
        case Role.STUDENT:
          setCurrentView(View.STUDENT_DASHBOARD);
          break;
        case Role.TEACHER:
          setCurrentView(View.TEACHER_DASHBOARD);
          break;
        case Role.ADMIN:
          setCurrentView(View.ADMIN_DASHBOARD);
          break;
      }
    } else {
      // In a real app, you would show an error message.
      console.error("Login failed");
      alert("Login Gagal! Pastikan username dan peran Anda benar.");
    }
  }, []);

  const registerStudent = useCallback((studentData: StudentData) => {
    // In a real app, you'd save this to a backend.
    // For now, we store it temporarily to show the confirmation screen.
    const newStudentUser: User = {
        id: `user-${Date.now()}`,
        username: studentData.nisn,
        fullName: studentData.fullName,
        role: Role.STUDENT,
        details: studentData,
    };
    mockUsers.push(newStudentUser); // Add to mock DB
    mockNISNData[studentData.nisn] = studentData; // Add to mock NISN DB

    setTempStudentData(studentData);
    setCurrentView(View.CONFIRM_DATA);
  }, []);


  const confirmRegistration = useCallback(() => {
    setTempStudentData(null);
    setCurrentView(View.LOGIN);
  }, []);

  const logout = useCallback(() => {
    setCurrentUser(null);
    setActiveExamId(null);
    setLastExamResult(null);
    setCurrentView(View.LOGIN);
  }, []);

  const startExam = useCallback((examId: string) => {
    setActiveExamId(examId);
    setCurrentView(View.EXAM_SESSION);
  }, []);

  const finishExam = useCallback((result: ExamResult) => {
    setLastExamResult(result);
    setActiveExamId(null);
    setCurrentView(View.EXAM_END_SCREEN);
  }, []);

  const returnToDashboard = useCallback(() => {
      setLastExamResult(null);
      if(currentUser?.role === Role.STUDENT) {
          setCurrentView(View.STUDENT_DASHBOARD);
      } else {
          logout(); // Fallback to login if something is wrong
      }
  }, [currentUser, logout]);


  const authContextValue = useMemo(() => ({
    user: currentUser,
    login,
    logout,
    registerStudent,
  }), [currentUser, login, logout, registerStudent]);

  const renderContent = () => {
    switch (currentView) {
      case View.LOGIN:
        return <Login onRegisterClick={() => setCurrentView(View.REGISTER)} />;
      case View.REGISTER:
        return <Register onLoginClick={() => setCurrentView(View.LOGIN)} />;
      case View.CONFIRM_DATA:
        return tempStudentData && <ConfirmData studentData={tempStudentData} onConfirm={confirmRegistration} />;

      case View.STUDENT_DASHBOARD:
        return currentUser && <StudentDashboard user={currentUser} onStartExam={startExam} logout={logout} />;
      case View.TEACHER_DASHBOARD:
        return currentUser && <TeacherDashboard user={currentUser} logout={logout} />;
      case View.ADMIN_DASHBOARD:
        return currentUser && <AdminDashboard user={currentUser} logout={logout} />;

      case View.EXAM_SESSION:
        return activeExamId && <ExamInterface examId={activeExamId} onFinishExam={finishExam} />;
      case View.EXAM_END_SCREEN:
        return lastExamResult && <ExamEndScreen result={lastExamResult} onReturnToDashboard={returnToDashboard} />;

      default:
        return <Login onRegisterClick={() => setCurrentView(View.REGISTER)} />;
    }
  };

  return (
    <AuthContext.Provider value={authContextValue}>
      <div className={`relative min-h-screen w-full bg-gray-100 dark:bg-slate-900 text-slate-800 dark:text-slate-200 overflow-hidden transition-colors duration-300 ${isDarkMode ? 'dark' : ''}`}>
        <AuroraBackground />
        <ThemeToggle isDarkMode={isDarkMode} toggleTheme={toggleTheme} />
        <main className="relative z-10 flex items-center justify-center min-h-screen p-4">
          {renderContent()}
        </main>
      </div>
    </AuthContext.Provider>
  );
};

export default App;

