            case 'ipa':
                return <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={1.5}><path strokeLinecap="round" strokeLinejoin="round" d="M14.25 10.5a8.25 8.25 0 01-8.25 8.25V18a8.25 8.25 0 018.25-8.25z" /><path strokeLinecap="round" strokeLinejoin="round" d="M14.25 10.5h.008v.008h-.008V10.5z" /><path strokeLinecap="round" strokeLinejoin="round" d="M15.75 12a3.75 3.75 0 11-7.5 0 3.75 3.75 0 017.5 0z" /></svg>;
