                            type="file" 
                            ref={fileInputRef}
                            className="hidden" 
                            onChange={handleFileChange} 
                            accept=".docx,.xlsx" 
                        />

                        <div className="flex items-center gap-4 p-3 bg-white/50 dark:bg-slate-800/60 rounded-lg border border-slate-300/80 dark:border-slate-700/80">
                            <Button 
                                type="button" 
                                variant="secondary" 
                                onClick={handleSelectFileClick}
                                className="flex-shrink-0 flex items-center gap-2"
                            >
                                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                                    <path strokeLinecap="round" strokeLinejoin="round" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0L8 8m4-4v12" />
                                </svg>
                                Pilih File...
                            </Button>
                            <span className="text-sm text-slate-600 dark:text-slate-300 truncate flex-grow">
                                {selectedFile ? selectedFile.name : 'Tidak ada file yang dipilih'}
                            </span>
                        </div>

                        <Button onClick={handleImport} disabled={isParsing || !selectedFile} className="mt-4 w-full">
                            {isParsing ? <Spinner /> : 'Impor Sekarang'}
                        </Button>
                        {importMessage && <p className={`mt-4 text-sm font-medium p-3 rounded-lg ${importMessage.type === 'success' ? 'bg-emerald-100 text-emerald-800 dark:bg-emerald-900/30 dark:text-emerald-300' : 'bg-red-100 text-red-800 dark:bg-red-900/30 dark:text-red-300'}`}>{importMessage.text}</p>}
                    </div>
                    <div className="bg-white/30 dark:bg-slate-900/50 p-6 rounded-lg text-sm text-slate-700 dark:text-slate-300">
                        <h3 className="text-xl font-semibold text-slate-800 dark:text-white mb-4">Petunjuk Format</h3>
                        <div className="prose prose-sm dark:prose-invert max-w-none">
                            <p><strong>Format Excel (.xlsx):</strong></p>
                            <ul>
                                <li>Header: <code>content</code>, <code>type</code>, <code>subject</code>, <code>phase</code>, <code>optionA</code>..<code>E</code>, <code>correctAnswer</code>.</li>
                                <li><code>type</code>: "Pilihan Ganda" atau "Esai".</li>
                                <li><code>correctAnswer</code>: Huruf (A-E) untuk PG, teks untuk Esai.</li>
                            </ul>
                            <p><strong>Format Word (.docx):</strong></p>
                            <ul>
                                <li>Soal: <code>1. Teks soal...</code></li>
                                <li>Opsi: <code>A. Teks opsi...</code></li>
                                <li>Kunci: <code>KUNCI: B</code> atau <code>KUNCI: Teks jawaban esai...</code></li>
                                <li>Metadata: <code>[SUBJEK: Fisika] [FASE: F]</code></li>
                            </ul>
                        </div>
                    </div>
                </div>
            )}

            {activeTab === 'add' && (
                 <div className="bg-white/30 dark:bg-slate-900/50 p-6 rounded-lg mb-8">
                     <h3 className="text-xl font-semibold text-slate-800 dark:text-white mb-4">Tambah Soal Manual</h3>
                     <div className="space-y-4">
                        <textarea
                            placeholder="Tulis konten soal di sini..."
                            rows={4}
                            value={newQuestion.content}
                            onChange={(e) => handleNewQuestionChange('content', e.target.value)}
                            className="w-full bg-white/40 dark:bg-slate-800/50 border border-slate-300/80 dark:border-slate-700/80 rounded-lg text-slate-900 dark:text-white placeholder-slate-500 p-3 focus:ring-2 focus:ring-indigo-500"
                        />
                        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                           <Input label="Mata Pelajaran" value={newQuestion.subject} onChange={(e) => handleNewQuestionChange('subject', e.target.value)} />
                           <div>
                                <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-2">Fase</label>
                                <select value={newQuestion.phase} onChange={(e) => handleNewQuestionChange('phase', e.target.value)} className="w-full bg-white/40 dark:bg-slate-800/50 border border-slate-300/80 dark:border-slate-700/80 rounded-lg p-3 focus:ring-2 focus:ring-indigo-500">
