        }, 300);
    });
};

export const updateQuestion = async (updatedQuestion: Question): Promise<boolean> => {
    return new Promise(resolve => {
        setTimeout(() => {
            const index = mockQuestions.findIndex(q => q.id === updatedQuestion.id);
            if (index !== -1) {
                mockQuestions[index] = updatedQuestion;
                saveQuestions();
                resolve(true);
            } else {
                resolve(false);
            }
        }, 300);
    });
};

