                                    }`}
                                >
                                    {isCorrect ? (
                                        <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-emerald-600 dark:text-emerald-400 mr-3 flex-shrink-0" viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm3.707-9.293a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" /></svg>
                                    ) : (
                                        <div className="flex-shrink-0 w-6 h-6 border-2 border-slate-400 dark:border-slate-500 rounded-full flex items-center justify-center mr-3" />
                                    )}
                                    <span className="font-semibold mr-2">{optionLetters[index]}.</span>
                                    <span className="text-slate-800 dark:text-slate-200">{option.text}</span>
                                </div>
                            );
                        })}
                    </div>
                </div>
            )}

            {question.type === QuestionType.ESSAY && (
                <div>
                    <h3 className="font-bold text-lg mb-3 text-indigo-700 dark:text-indigo-300">Kunci Jawaban Esai</h3>
                     <p className="text-sm text-slate-700 dark:text-slate-300 bg-white/50 dark:bg-slate-800/50 p-4 rounded-md">{question.correctAnswer}</p>
                </div>
            )}
        </div>
    </div>
  );
};

export default QuestionDetail;

import React, { useState, useEffect } from 'react';
import { Question, QuestionType, QuestionOption, QuestionMediaType } from '../../types';
import { fetchQuestionById, updateQuestion } from '../../services/api';
import Button from '../ui/Button';
import Input from '../ui/Input';
import Spinner from '../ui/Spinner';

interface EditQuestionModalProps {
  questionId: string;
  onClose: () => void;
  onQuestionUpdated: (updatedQuestion: Question) => void;
}

const EditQuestionModal: React.FC<EditQuestionModalProps> = ({ questionId, onClose, onQuestionUpdated }) => {
  const [question, setQuestion] = useState<Question | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [isSaving, setIsSaving] = useState(false);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const loadQuestion = async () => {
      setIsLoading(true);
      setError(null);
      const data = await fetchQuestionById(questionId);
      if (data) {
        // Ensure mediaType defaults to TEXT if not present
        setQuestion({ ...data, mediaType: data.mediaType || QuestionMediaType.TEXT });
      } else {
        setError("Gagal memuat soal untuk diedit.");
      }
      setIsLoading(false);
    };
    loadQuestion();
  }, [questionId]);

  const handleInputChange = (field: keyof Question, value: any) => {
    if (question) {
        setQuestion({ ...question, [field]: value });
    }
  };

  const handleOptionTextChange = (optionId: string, text: string) => {
    if (question && question.options) {
        const newOptions = question.options.map(opt => 
            opt.id === optionId ? { ...opt, text } : opt
        );
        handleInputChange('options', newOptions);
    }
  };

  const handleCorrectAnswerChange = (optionId: string) => {
    if (question?.type === QuestionType.MULTIPLE_CHOICE) {
        handleInputChange('correctAnswer', optionId);
    }
  };

  const handleAddOption = () => {
    if (question && question.options && question.options.length < 5) {
        const newOption: QuestionOption = {
            id: `${question.id}-o${Date.now()}`,
            text: ''
        };
        const newOptions = [...question.options, newOption];
        handleInputChange('options', newOptions);
    }
  };

  const handleRemoveOption = (optionIdToRemove: string) => {
    if (question && question.options && question.options.length > 2) {
      const newOptions = question.options.filter(opt => opt.id !== optionIdToRemove);

      let newCorrectAnswer = question.correctAnswer;
      // If the deleted option was the correct answer, reset to the first remaining option
      if (question.correctAnswer === optionIdToRemove) {
        newCorrectAnswer = newOptions[0]?.id || '';
      }

      setQuestion({
        ...question,
        options: newOptions,
        correctAnswer: newCorrectAnswer,
      });
    }
  };

  const handleSaveChanges = async () => {
    if (!question) return;

    setIsSaving(true);
    setError(null);

    // Basic validation
    if (!question.subject.trim()) {
        setError("Mata pelajaran tidak boleh kosong.");
        setIsSaving(false);
        return;
    }
     if (question.mediaType === QuestionMediaType.TEXT) {
        if (!question.content.trim()) {
            setError("Konten soal tidak boleh kosong.");
            setIsSaving(false);
            return;
        }
    } else {
        if (!question.content.trim()) {
            setError("URL media tidak boleh kosong.");
            setIsSaving(false);
            return;
        }
        if (!question.promptText?.trim()) {
            setError("Teks pengantar media tidak boleh kosong.");
            setIsSaving(false);
            return;
        }
    }

    if (question.type === QuestionType.MULTIPLE_CHOICE) {
        const hasEmptyOption = question.options?.some(opt => opt.text.trim() === '');
        if (hasEmptyOption) {
            setError("Teks opsi jawaban tidak boleh kosong.");
            setIsSaving(false);
            return;
        }
    }

    const success = await updateQuestion(question);
    if (success) {
        onQuestionUpdated(question);
        onClose();
    } else {
        setError("Gagal menyimpan perubahan. Silakan coba lagi.");
    }
    setIsSaving(false);
  };

  const renderForm = () => {
    if (!question) return null;

    const mediaType = question.mediaType || QuestionMediaType.TEXT;

    return (
        <div className="space-y-4">
             <div>
                <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-2">Tipe Konten</label>
                <select value={mediaType} onChange={(e) => handleInputChange('mediaType', e.target.value)} className="w-full md:w-1/3 bg-white/40 dark:bg-slate-800/50 border border-slate-300/80 dark:border-slate-700/80 rounded-lg p-3">
                    <option value={QuestionMediaType.TEXT}>Teks</option>
                    <option value={QuestionMediaType.AUDIO}>Audio</option>
                    <option value={QuestionMediaType.VIDEO}>Video</option>
                </select>
            </div>
            {mediaType === QuestionMediaType.TEXT ? (
                 <div>
                    <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-2">Konten Soal</label>
                    <textarea
                        rows={4}
                        value={question.content}
                        onChange={(e) => handleInputChange('content', e.target.value)}
                        className="w-full bg-white/40 dark:bg-slate-800/50 border border-slate-300/80 dark:border-slate-700/80 rounded-lg p-3"
                    />
                </div>
            ) : (
                <div className='space-y-4'>
                    <Input label="URL Media (Google Drive / YouTube)" value={question.content} onChange={(e) => handleInputChange('content', e.target.value)} placeholder="https://..."/>
                     <div>
                        <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-2">Teks Pengantar Media</label>
                        <textarea
                            rows={3}
                            value={question.promptText || ''}
                            onChange={(e) => handleInputChange('promptText', e.target.value)}
                            className="w-full bg-white/40 dark:bg-slate-800/50 border border-slate-300/80 dark:border-slate-700/80 rounded-lg p-3"
                        />
                    </div>
                </div>
            )}

             <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <Input label="Mata Pelajaran" value={question.subject} onChange={(e) => handleInputChange('subject', e.target.value)} />
                <div>
                    <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-2">Fase</label>
                    <select value={question.phase} onChange={(e) => handleInputChange('phase', e.target.value)} className="w-full bg-white/40 dark:bg-slate-800/50 border border-slate-300/80 dark:border-slate-700/80 rounded-lg p-3">
                        <option value="D">Fase D (SMP)</option>
                        <option value="E">Fase E (SMA)</option>
                        <option value="F">Fase F (SMA)</option>
                    </select>
                </div>
            </div>
            {question.type === QuestionType.MULTIPLE_CHOICE && question.options && (
                <div className="pt-4 border-t border-white/20 dark:border-slate-700/50">
                    <h4 className="text-lg font-semibold mb-2">Opsi Jawaban</h4>
                    <div className="space-y-3">
                        {question.options.map((opt, index) => (
                            <div key={opt.id} className="flex items-center gap-3">
                                <input type="radio" name="correctAnswer" checked={question.correctAnswer === opt.id} onChange={() => handleCorrectAnswerChange(opt.id)} className="h-5 w-5 text-indigo-600"/>
                                <span className="font-semibold">{String.fromCharCode(65 + index)}.</span>
                                <Input label="" value={opt.text} onChange={(e) => handleOptionTextChange(opt.id, e.target.value)} className="flex-grow !mb-0"/>
                                {question.options && question.options.length > 2 && (
                                    <button
                                        type="button"
                                        onClick={() => handleRemoveOption(opt.id)}
                                        className="p-2 rounded-full text-slate-500 hover:bg-red-100 hover:text-red-600 dark:hover:bg-red-900/50 dark:hover:text-red-400 transition-colors flex-shrink-0"
                                        title="Hapus Opsi"
                                    >
                                        <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                                            <path strokeLinecap="round" strokeLinejoin="round" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                                        </svg>
                                    </button>
                                )}
                            </div>
                        ))}
                    </div>
                     <div className="mt-4">
                        <Button
                            type="button"
                            variant="secondary"
                            onClick={handleAddOption}
                            disabled={question.options.length >= 5}
                            className="text-sm py-2 px-3"
                        >
                            + Tambah Opsi Jawaban
                        </Button>
                    </div>
                </div>
            )}
            {question.type === QuestionType.ESSAY && (
                 <div className="pt-4 border-t border-white/20 dark:border-slate-700/50">
                    <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-2">Kunci Jawaban Esai</label>
                    <textarea
                        rows={3}
                        value={question.correctAnswer}
                        onChange={(e) => handleInputChange('correctAnswer', e.target.value)}
                        className="w-full bg-white/40 dark:bg-slate-800/50 border border-slate-300/80 dark:border-slate-700/80 rounded-lg p-3"
                    />
                </div>
            )}
        </div>
    );
  }

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm" onClick={onClose}>
      <div 
        className="w-full max-w-2xl bg-slate-100 dark:bg-slate-800 rounded-2xl shadow-2xl p-8 transform transition-all overflow-y-auto max-h-[90vh]"
        onClick={e => e.stopPropagation()}
      >
        <div className="flex justify-between items-center mb-6">
            <h2 className="text-2xl font-bold text-slate-800 dark:text-white">Edit Soal</h2>
            <button onClick={onClose} className="p-2 rounded-full hover:bg-slate-200 dark:hover:bg-slate-700">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
            </button>
        </div>

        <div className="pr-2">
            {isLoading && <div className="text-center p-8"><Spinner /></div>}
            {!isLoading && !question && <p className="text-red-500">{error || "Soal tidak ditemukan."}</p>}
            {!isLoading && question && renderForm()}
        </div>


        {error && <p className="text-red-500 text-sm mt-4">{error}</p>}

        <div className="flex justify-end gap-4 mt-8 border-t border-slate-200 dark:border-slate-700 pt-6">
            <Button variant="secondary" onClick={onClose}>Batal</Button>
            <Button onClick={handleSaveChanges} disabled={isSaving || isLoading}>
                {isSaving ? <Spinner size="small" /> : 'Simpan Perubahan'}
            </Button>
        </div>
      </div>
    </div>
  );
};

export default EditQuestionModal;

payload.text:
Tentu, ini adalah pertanyaan yang sangat penting.

Secara langsung, **TIDAK**, kode yang telah saya buat ini **tidak bisa langsung di-copy-paste dan dijalankan di dalam editor Google Apps Script**.

Berikut adalah penjelasan rincinya mengapa demikian dan bagaimana cara yang benar untuk membuatnya bekerja dengan Google Apps Script sebagai backend.

### Mengapa Tidak Bisa Langsung Dijalankan?

1.  **Lingkungan yang Berbeda**: Kode yang saya berikan adalah aplikasi **React** modern. Ini menggunakan:
    *   **JSX**: Sintaks seperti `<Button>Klik Saya</Button>` yang merupakan gabungan HTML dan JavaScript. Google Apps Script (.gs) tidak mengerti JSX.
    *   **ES Modules**: `import` dan `export` untuk mengorganisir kode. Apps Script memiliki cara kerjanya sendiri dan tidak mendukung sistem modul ini secara native.
    *   **React & ReactDOM**: Ini adalah library eksternal yang perlu di-bundle atau dimuat.
    *   **Local Development Server**: Aplikasi seperti ini biasanya dijalankan di komputer lokal dengan server pengembangan (seperti Vite atau Create React App) sebelum di-build menjadi file statis.

2.  **Pemisahan Frontend & Backend**: Aplikasi modern memisahkan antara tampilan (Frontend, yang berjalan di browser pengguna) dan logika server (Backend).
    *   **Frontend kita (React)**: Bertugas menampilkan antarmuka yang indah dan interaktif.
    *   **Backend yang Anda inginkan (Google Apps Script)**: Bertugas mengelola data di Google Sheets, menangani registrasi, mengambil soal, dll.

### Solusi yang Tepat: Menjadikan Apps Script sebagai API Backend

Cara yang benar adalah dengan memadukan kekuatan keduanya. Kita akan tetap menggunakan **React** untuk membuat tampilan antarmuka yang canggih dan menggunakan **Google Apps Script** sebagai backend gratis yang terhubung langsung ke **Google Sheets** sebagai database.

Berikut adalah arsitektur dan langkah-langkahnya:

---

#### Struktur Proyek yang Disarankan

Anda akan memiliki dua bagian utama dalam proyek Anda:

1.  **Proyek React (di Komputer Lokal Anda)**:
    *   Semua file `.tsx`, `.ts`, `.html` yang sudah saya berikan.
    *   Anda akan menggunakan `npm` atau `yarn` untuk menginstal dependensi dan menjalankan server development.
    *   Setelah selesai, Anda akan **membangun (build)** proyek ini menjadi beberapa file statis (HTML, JavaScript, CSS).

2.  **Proyek Google Apps Script (di `script.google.com`)**:
    *   `Code.gs`: Berisi semua logika backend (API).
    *   `index.html`: File HTML sederhana untuk menampung aplikasi React yang sudah di-build.
    *   **Google Sheet**: Bertindak sebagai database Anda.

---

### Langkah-langkah Implementasi

#### Langkah 1: Siapkan Database Google Sheets

Buatlah Google Sheet baru dengan beberapa tab (sheet): `Users`, `Questions`, `Exams`, `NISN_Data`.

*   **Sheet `Users`**:
    *   Kolom: `id`, `username`, `fullName`, `role`, `details (JSON string)`
*   **Sheet `Questions`**:
    *   Kolom: `id`, `type`, `mediaType`, `promptText`, `content`, `options (JSON string)`, `correctAnswer`, `phase`, `subject`
*   **Sheet `NISN_Data`**:
    *   Kolom: `nisn`, `fullName`, `class`, `school`, `city`, `province`

#### Langkah 2: Buat Backend di Google Apps Script (`Code.gs`)

Ini adalah bagian terpenting. Logika yang ada di `services/api.ts` akan kita pindahkan ke sini dan diubah untuk berinteraksi dengan Google Sheets.

```javascript
// File: Code.gs

const SPREADSHEET_ID = "ID_SPREADSHEET_ANDA"; // Ganti dengan ID Spreadsheet Anda
const usersSheet = SpreadsheetApp.openById(SPREADSHEET_ID).getSheetByName("Users");
const questionsSheet = SpreadsheetApp.openById(SPREADSHEET_ID).getSheetByName("Questions");
const nisnDataSheet = SpreadsheetApp.openById(SPREADSHEET_ID).getSheetByName("NISN_Data");

// Fungsi ini akan menyajikan file HTML utama
function doGet(e) {
  return HtmlService.createHtmlOutputFromFile('index.html')
      .setTitle("CBT Kurikulum Merdeka")
      .addMetaTag('viewport', 'width=device-width, initial-scale=1.0');
}

// --- API Functions --- //

// Fungsi untuk mencari data NISN
function fetchNISNData_GS(nisn) {
  const data = nisnDataSheet.getDataRange().getValues();
  // Mulai dari 1 untuk melewati header
  for (let i = 1; i < data.length; i++) {
    if (data[i][0] == nisn) { // Kolom 0 adalah NISN
      return {
        nisn: data[i][0],
        fullName: data[i][1],
        class: data[i][2],
        school: data[i][3],
        city: data[i][4],
        province: data[i][5],
      };
    }
  }
  return null;
}

// Fungsi untuk mendaftarkan siswa baru
function registerNewStudent_GS(studentData) {
  // Cek apakah user sudah ada
  const users = usersSheet.getDataRange().getValues();
  for (let i = 1; i < users.length; i++) {
    if (users[i][1] == studentData.nisn) { // Kolom 1 adalah username/nisn
      return { user: null, error: 'Pengguna dengan NISN ini sudah terdaftar.' };
    }
  }

  // Tambah user baru
  const newId = "user-" + new Date().getTime();
  usersSheet.appendRow([
    newId,
    studentData.nisn,
    studentData.fullName,
    "Siswa", // Role
    JSON.stringify(studentData) // details
  ]);

  return { 
      user: { 
          id: newId, 
          username: studentData.nisn, 
          fullName: studentData.fullName, 
          role: "Siswa", 
          details: studentData 
      }, 
      error: null 
  };
}

// Fungsi untuk login
function login_GS(username, role) {
  const data = usersSheet.getDataRange().getValues();
  for (let i = 1; i < data.length; i++) {
    if (data[i][1].toLowerCase() === username.toLowerCase() && data[i][3] === role) {
      return {
        id: data[i][0],
        username: data[i][1],
        fullName: data[i][2],
        role: data[i][3],
        details: JSON.parse(data[i][4] || '{}')
      };
    }
  }
  return null;
}

// ... Tambahkan fungsi-fungsi lain seperti getExams_GS, getQuestionsByIds_GS, dll.
```

#### Langkah 3: Modifikasi Frontend untuk Memanggil Apps Script

Di proyek React lokal Anda, ubah `services/api.ts`. Alih-alih menggunakan data mock, kita akan menggunakan `google.script.run` untuk memanggil fungsi di `Code.gs`.

```typescript
// File: services/api.ts (versi modifikasi)

// ... (impor tipe data tetap sama)

// Helper untuk membungkus google.script.run dalam Promise
const gscriptRun = (functionName: string, ...args: any[]): Promise<any> => {
  return new Promise((resolve, reject) => {
    google.script.run
      .withSuccessHandler(resolve)
      .withFailureHandler(reject)
      [functionName](...args);
  });
};

// Mock API functions diganti dengan panggilan ke Apps Script
export const fetchNISNData = async (nisn: string): Promise<StudentData | null> => {
    return await gscriptRun('fetchNISNData_GS', nisn);
};

export const registerNewStudent = async (studentData: StudentData): Promise<{user: User | null, error?: string}> => {
    return await gscriptRun('registerNewStudent_GS', studentData);
};

// Implementasikan semua fungsi lainnya dengan pola yang sama...
// Contoh:
export const loginUser = async (username: string, role: Role): Promise<User | null> => {
    return await gscriptRun('login_GS', username, role);
}

// ...
```

#### Langkah 4: Build Aplikasi React

1.  Di komputer lokal Anda, jalankan perintah `npm run build` (atau `yarn build`).
2.  Ini akan membuat folder `dist` (atau `build`) yang berisi file `index.html`, dan file JavaScript serta CSS yang sudah dioptimalkan (misalnya `assets/index-a1b2c3d4.js`).

#### Langkah 5: Unggah Hasil Build ke Apps Script

1.  Buka proyek Apps Script Anda.
2.  Buat file HTML baru bernama `index.html`.
3.  **Copy-paste isi dari `dist/index.html`** ke dalam `index.html` Apps Script.
4.  **Copy-paste isi dari file JavaScript yang di-generate (misal `dist/assets/index-a1b2c3d4.js`)** ke dalam tag `<script>` di dalam file `index.html` Apps Script, atau unggah ke layanan hosting statis dan tautkan dari sana.
5.  Lakukan hal yang sama untuk file CSS.

#### Langkah 6: Deploy sebagai Web App

1.  Di editor Apps Script, klik `Deploy` > `New deployment`.
2.  Pilih `Web app`.
3.  Pada "Execute as", pilih "Me".
4.  Pada "Who has access", pilih "Anyone" (atau "Anyone within your organization").
5.  Klik `Deploy`. Anda akan mendapatkan URL Web App Anda.

Sekarang, URL tersebut akan menyajikan aplikasi React Anda yang canggih, dengan semua data dan logika dikelola oleh Google Apps Script dan Google Sheets.

### Kesimpulan

-   **Bisa?** Ya, sangat bisa dan ini adalah cara yang sangat powerful.
-   **Langsung?** Tidak.
-   **Cara Kerja:** Gunakan React untuk membangun antarmuka (frontend) dan Google Apps Script sebagai API server (backend) yang terhubung ke Google Sheets.

Ini adalah pendekatan modern yang menggabungkan UI terbaik dengan backend yang gratis dan mudah dikelola.

