    const [selectedSubject, setSelectedSubject] = useState('all');
    const [selectedPhase, setSelectedPhase] = useState('all');


    const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
        if (event.target.files && event.target.files.length > 0) {
            setSelectedFile(event.target.files[0]);
            setImportMessage(null);
        }
    };

    const handleSelectFileClick = () => {
        fileInputRef.current?.click();
    };

    const handleClearFile = () => {
        setSelectedFile(null);
        setImportMessage(null);
        if (fileInputRef.current) {
            fileInputRef.current.value = '';
        }
    };

    const handleQuestionUpdated = (updatedQuestion: Question) => {
        setQuestions(prevQuestions =>
            prevQuestions.map(q =>
                q.id === updatedQuestion.id ? updatedQuestion : q
            )
        );
        // Also update in detail view if it's the same question
        if(selectedQuestionId === updatedQuestion.id){
            setSelectedQuestionId(null); // force re-render or handle state better
            setTimeout(() => setSelectedQuestionId(updatedQuestion.id), 0);
        }
    };

    const handleImport = async () => {
        if (!selectedFile) {
            setImportMessage({ type: 'error', text: 'Silakan pilih file terlebih dahulu.' });
            return;
        }
        setIsParsing(true);
        setImportMessage(null);

        try {
            let newQuestions: Question[] = [];
            if (selectedFile.name.endsWith('.xlsx')) {
                newQuestions = await parseXLSX(selectedFile);
            } else if (selectedFile.name.endsWith('.docx')) {
                newQuestions = await parseDOCX(selectedFile);
            } else {
                throw new Error('Format file tidak didukung. Gunakan .xlsx atau .docx');
            }

            if (newQuestions.length > 0) {
                await addQuestions(newQuestions);
                setQuestions(prev => [...prev, ...newQuestions]);
                setImportMessage({ type: 'success', text: `Berhasil! ${newQuestions.length} soal baru telah ditambahkan ke bank soal Anda.` });
            } else {
                setImportMessage({ type: 'error', text: 'Tidak ada soal yang dapat diimpor dari file. Periksa format file Anda.' });
            }
        } catch (error: any) {
            setImportMessage({ type: 'error', text: `Gagal mengimpor: ${error.message}` });
        } finally {
            setIsParsing(false);
            if (fileInputRef.current) {
               fileInputRef.current.value = '';
            }
            setSelectedFile(null);
        }
    };

    const handleNewQuestionChange = (field: keyof typeof newQuestion, value: any) => {
        setNewQuestion(prev => ({ ...prev, [field]: value }));
    };

    const handleOptionChange = (index: number, value: string) => {
        const updatedOptions = [...newQuestion.options];
        updatedOptions[index] = { text: value };
        handleNewQuestionChange('options', updatedOptions);
    };

    const handleAddQuestion = async () => {
        setAddMessage(null);
        setIsAdding(true);

        try {
            if (!newQuestion.subject.trim()) {
                 throw new Error('Mata pelajaran wajib diisi.');
            }

            const questionToAdd: Question = {
                id: `manual-${Date.now()}`,
                content: '',
                type: newQuestion.type,
                mediaType: newQuestion.mediaType,
                subject: newQuestion.subject.trim(),
                phase: newQuestion.phase,
                correctAnswer: '',
                options: [],
            };

            if (newQuestion.mediaType === QuestionMediaType.TEXT) {
                if (!newQuestion.content.trim()) throw new Error('Konten soal wajib diisi.');
                questionToAdd.content = newQuestion.content.trim();
            } else {
                if (!newQuestion.mediaUrl.trim()) throw new Error('URL Media wajib diisi.');
                if (!newQuestion.promptText.trim()) throw new Error('Teks Pengantar Media wajib diisi.');
                questionToAdd.content = newQuestion.mediaUrl.trim();
                questionToAdd.promptText = newQuestion.promptText.trim();
            }

            if (newQuestion.type === QuestionType.MULTIPLE_CHOICE) {
                const validOptions = newQuestion.options.filter(opt => opt.text.trim() !== '');
                if (validOptions.length < 2) {
                    throw new Error('Pilihan ganda harus memiliki minimal 2 opsi jawaban yang valid.');
                }
                if (newQuestion.options[newQuestion.correctAnswerIndex].text.trim() === '') {
                    throw new Error('Kunci jawaban yang dipilih tidak boleh kosong.');
                }

                questionToAdd.options = validOptions.map((opt, i) => ({ id: `${questionToAdd.id}-o${i+1}`, text: opt.text }));

                const correctOptionText = newQuestion.options[newQuestion.correctAnswerIndex].text;
                const newCorrectIndex = validOptions.findIndex(opt => opt.text === correctOptionText);

                if (newCorrectIndex === -1) {
                    throw new Error('Kunci jawaban yang dipilih tidak valid atau tidak diisi.');
                }
                questionToAdd.correctAnswer = questionToAdd.options[newCorrectIndex].id;

            } else { // Essay
                if (!newQuestion.essayAnswer.trim()) {
                    throw new Error('Kunci jawaban esai wajib diisi.');
                }
                questionToAdd.correctAnswer = newQuestion.essayAnswer.trim();
                delete questionToAdd.options;
            }

            await addQuestions([questionToAdd]);
            setQuestions(prev => [questionToAdd, ...prev]);
            setAddMessage({ type: 'success', text: 'Soal berhasil ditambahkan!' });

            // Reset form
            setNewQuestion({
                content: '', mediaType: QuestionMediaType.TEXT, mediaUrl: '', promptText: '',
                type: QuestionType.MULTIPLE_CHOICE, subject: '', phase: 'F',
                options: [{ text: '' }, { text: '' }, { text: '' }, { text: '' }, { text: '' }],
                correctAnswerIndex: 0, essayAnswer: ''
            });

        } catch (error: any) {
            setAddMessage({ type: 'error', text: error.message });
        } finally {
            setIsAdding(false);
        }
    };

    const uniqueSubjects = useMemo(() => {
        const subjects = new Set(questions.map(q => q.subject));
        return ['all', ...Array.from(subjects).sort()];
    }, [questions]);

    const subjectCounts = useMemo(() => {
        return questions.reduce((acc, q) => {
            acc[q.subject] = (acc[q.subject] || 0) + 1;
            return acc;
        }, {} as Record<string, number>);
    }, [questions]);

    const filteredQuestions = useMemo(() => {
        return questions.filter(q => {
            const contentToSearch = q.mediaType === QuestionMediaType.TEXT ? q.content : q.promptText || '';
            const searchMatch = contentToSearch.toLowerCase().includes(searchQuery.toLowerCase());
            const subjectMatch = selectedSubject === 'all' || q.subject === selectedSubject;
            const phaseMatch = selectedPhase === 'all' || q.phase === selectedPhase;
            return searchMatch && subjectMatch && phaseMatch;
        });
    }, [questions, searchQuery, selectedSubject, selectedPhase]);

    const handleResetFilters = () => {
        setSearchQuery('');
        setSelectedSubject('all');
        setSelectedPhase('all');
    };

    const handleExportToCSV = () => {
        if (filteredQuestions.length === 0) {
            alert("Tidak ada soal untuk diekspor.");
            return;
        }

        const escapeCSV = (str: string) => `"${String(str).replace(/"/g, '""')}"`;

        const headers = [
            'id', 'content', 'type', 'subject', 'phase', 
            'optionA', 'optionB', 'optionC', 'optionD', 'optionE', 
            'correctAnswer'
        ];

        const rows = filteredQuestions.map(q => {
            const row: { [key: string]: string } = {
                id: q.id,
                content: q.content,
                type: q.type,
                subject: q.subject,
                phase: q.phase,
            };

            if (q.type === QuestionType.MULTIPLE_CHOICE && q.options) {
                const optionLetters = ['A', 'B', 'C', 'D', 'E'];
                q.options.forEach((opt, index) => {
                    row[`option${optionLetters[index]}`] = opt.text;
                });

                const correctIndex = q.options.findIndex(opt => opt.id === q.correctAnswer);
                row.correctAnswer = correctIndex !== -1 ? optionLetters[correctIndex] : '';
            } else { // Essay
                row.correctAnswer = q.correctAnswer;
            }

            return headers.map(header => escapeCSV(row[header] || '')).join(',');
        });

        const csvContent = [headers.join(','), ...rows].join('\n');
        const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
        const url = URL.createObjectURL(blob);
        const link = document.createElement("a");
        link.setAttribute("href", url);
        link.setAttribute("download", `bank_soal_${new Date().toISOString().slice(0,10)}.csv`);
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
    };

    const parseXLSX = (file: File): Promise<Question[]> => {
        return new Promise((resolve, reject) => {
            const reader = new FileReader();
            reader.onload = (e) => {
                try {
                    const data = new Uint8Array(e.target?.result as ArrayBuffer);
                    const workbook = XLSX.read(data, { type: 'array' });
                    const sheetName = workbook.SheetNames[0];
                    const worksheet = workbook.Sheets[sheetName];
                    const json = XLSX.utils.sheet_to_json(worksheet) as any[];

                    const parsedQuestions: Question[] = json.map((row, index) => {
                        const rowNum = index + 2;
                        const requiredFields = ['content', 'type', 'subject', 'phase', 'correctAnswer'];
                        for (const field of requiredFields) {
                            if (!row[field] || String(row[field]).trim() === '') {
                                throw new Error(`Kolom '${field}' kosong pada baris ${rowNum}`);
                            }
                        }

                        const type = String(row['type']).trim();
                        if (type !== 'Pilihan Ganda' && type !== 'Esai') {
                            throw new Error(`Nilai kolom 'type' tidak valid pada baris ${rowNum}. Gunakan "Pilihan Ganda" atau "Esai".`);
                        }

                        const phase = String(row['phase']).trim().toUpperCase();
                        if (!['D', 'E', 'F'].includes(phase)) {
                            throw new Error(`Nilai kolom 'phase' tidak valid pada baris ${rowNum}. Gunakan "D", "E", atau "F".`);
                        }

                        const question: Question = {
                            id: `imported-${Date.now()}-${index}`,
                            content: String(row['content']).trim(),
                            type: type === 'Pilihan Ganda' ? QuestionType.MULTIPLE_CHOICE : QuestionType.ESSAY,
                            subject: String(row['subject']).trim(),
                            phase: phase as 'D' | 'E' | 'F',
                            correctAnswer: String(row['correctAnswer']).trim(),
                            options: [],
                        };

                        if (question.type === QuestionType.MULTIPLE_CHOICE) {
                            question.options = ['A', 'B', 'C', 'D', 'E']
                                .map((opt, i) => ({ id: `${question.id}-o${i + 1}`, text: row[`option${opt}`] }))
                                .filter(opt => opt.text && String(opt.text).trim() !== '');

                            if (question.options.length < 2) {
                                throw new Error(`Soal Pilihan Ganda pada baris ${rowNum} harus memiliki setidaknya 2 opsi.`);
                            }

                            const correctLetter = String(row['correctAnswer']).trim().toUpperCase();
                            if (!row[`option${correctLetter}`] || String(row[`option${correctLetter}`]).trim() === '') {
                                throw new Error(`Kunci jawaban "${correctLetter}" tidak valid atau opsinya kosong pada baris ${rowNum}`);
                            }

                            const correctOptionText = String(row[`option${correctLetter}`]).trim();
                            const finalCorrectOption = question.options.find(opt => opt.text.trim() === correctOptionText);

                            if (!finalCorrectOption) {
                                throw new Error(`Kunci jawaban pada baris ${rowNum} tidak cocok dengan opsi yang valid.`);
                            }
                            question.correctAnswer = finalCorrectOption.id;
                        }
                        return question;
                    });
                    resolve(parsedQuestions);
                } catch (err: any) { reject(err); }
            };
            reader.onerror = reject; reader.readAsArrayBuffer(file);
        });
    };

    const parseDOCX = (file: File): Promise<Question[]> => {
         return new Promise((resolve, reject) => {
            const reader = new FileReader();
            reader.onload = async (e) => {
                 try {
                    const arrayBuffer = e.target?.result as ArrayBuffer;
                    const { value: text } = await mammoth.extractRawText({ arrayBuffer });
                    const questionsText = text.split(/(?=\d+\.\s)/).filter(Boolean);
                    if (questionsText.length === 0) throw new Error("Tidak ada soal yang ditemukan dalam format yang dikenali.");

                    const parsedQuestions: Question[] = questionsText.map((qText, index) => {
                        const questionNum = index + 1;
                        const contentMatch = qText.match(/^\d+\.\s([\s\S]*?)(?=\n[A-E]\.|\nKUNCI:)/);
                        const content = contentMatch ? contentMatch[1].trim() : '';
                        if (!content) throw new Error(`Konten soal no. ${questionNum} tidak ditemukan.`);

                        const optionsMatches = [...qText.matchAll(/([A-E])\.\s(.*?)(?=\n[A-E]\.|\nKUNCI:|$)/gs)];
                        const options: QuestionOption[] = optionsMatches.map((match, i) => ({ id: `imported-${Date.now()}-${index}-o${i + 1}`, text: match[2].trim() }));

                        const subjectMatch = qText.match(/\[SUBJEK:\s*(.*?)\]/i);
                        if (!subjectMatch || !subjectMatch[1].trim()) throw new Error(`Metadata [SUBJEK] tidak ditemukan atau kosong untuk soal no. ${questionNum}.`);

                        const phaseMatch = qText.match(/\[FASE:\s*(.*?)\]/i);
                        if (!phaseMatch || !phaseMatch[1].trim()) throw new Error(`Metadata [FASE] tidak ditemukan atau kosong untuk soal no. ${questionNum}.`);

                        const phase = phaseMatch[1].trim().toUpperCase();
                        if (!['D', 'E', 'F'].includes(phase)) {
                            throw new Error(`Nilai fase "${phase}" tidak valid untuk soal no. ${questionNum}. Gunakan D, E, atau F.`);
                        }

                        const type = options.length > 0 ? QuestionType.MULTIPLE_CHOICE : QuestionType.ESSAY;
                        let correctAnswer = '';

                        if (type === QuestionType.MULTIPLE_CHOICE) {
                            if (options.length < 2) throw new Error(`Soal pilihan ganda no. ${questionNum} harus memiliki minimal 2 opsi.`);

                            const correctAnswerMatch = qText.match(/KUNCI:\s*([A-E])/i);
                            if (!correctAnswerMatch) throw new Error(`Kunci jawaban tidak ditemukan untuk soal pilihan ganda no. ${questionNum}.`);

                            const correctLetter = correctAnswerMatch[1].toUpperCase();
                            const correctIndex = ['A', 'B', 'C', 'D', 'E'].indexOf(correctLetter);
                            if (correctIndex === -1 || !options[correctIndex]) throw new Error(`Kunci jawaban "${correctLetter}" tidak valid untuk soal no. ${questionNum}.`);
                            correctAnswer = options[correctIndex].id;
                        } else { // Essay
                            const essayAnswerMatch = qText.match(/KUNCI:\s*([\s\S]*?)(?=\n\[|$)/i);
                            if (!essayAnswerMatch || !essayAnswerMatch[1].trim()) throw new Error(`Kunci jawaban esai tidak ditemukan atau kosong untuk soal no. ${questionNum}.`);
                            correctAnswer = essayAnswerMatch[1].trim();
                        }
                        return { id: `imported-${Date.now()}-${index}`, content, options: type === QuestionType.MULTIPLE_CHOICE ? options : undefined, type, correctAnswer, subject: subjectMatch[1].trim(), phase: phase as 'D' | 'E' | 'F' };
                    });
                    resolve(parsedQuestions);
                } catch (err: any) { reject(err); }
            };
            reader.onerror = reject; reader.readAsArrayBuffer(file);
        });
    };

    if (selectedQuestionId) {
        return <QuestionDetail questionId={selectedQuestionId} onBack={() => setSelectedQuestionId(null)} />;
    }

    return (
        <div>
            {editingQuestionId && (
                <EditQuestionModal
                    questionId={editingQuestionId}
                    onClose={() => setEditingQuestionId(null)}
                    onQuestionUpdated={handleQuestionUpdated}
                />
            )}
            <h2 className="text-2xl font-bold text-slate-800 dark:text-white mb-4">Bank Soal</h2>

            <div className="flex border-b border-white/20 dark:border-slate-700/50 mb-6">
                <TabButton name="import" activeTab={activeTab} setActiveTab={setActiveTab}>Impor Massal</TabButton>
                <TabButton name="add" activeTab={activeTab} setActiveTab={setActiveTab}>Tambah Manual</TabButton>
            </div>

            {activeTab === 'import' && (
                <div className="grid grid-cols-1 md:grid-cols-2 gap-8 mb-8">
                    <div className="bg-white/30 dark:bg-slate-900/50 p-6 rounded-lg">
                        <h3 className="text-xl font-semibold text-slate-800 dark:text-white mb-4">Impor Soal Baru</h3>
                        <p className="text-slate-600 dark:text-slate-300 mb-4 text-sm">Unggah file .docx atau .xlsx untuk menambahkan soal secara massal.</p>

                        <input 
                            id="file-input" 
                            type="file" 
                            ref={fileInputRef}
                            className="hidden" 
                            onChange={handleFileChange} 
                            accept=".docx,.xlsx" 
                        />

                        <div className={`p-4 border-2 border-dashed rounded-lg transition-colors ${selectedFile ? 'border-indigo-400 bg-indigo-50 dark:bg-indigo-900/30' : 'border-slate-400/50 dark:border-slate-600/50 hover:border-indigo-400'}`}>
                            {selectedFile ? (
                                <div className="flex items-center justify-between">
                                    <div className="flex items-center gap-3 overflow-hidden">
                                        <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8 text-slate-500 dark:text-slate-400 flex-shrink-0" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={1.5}><path strokeLinecap="round" strokeLinejoin="round" d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg>
                                        <span className="text-sm font-medium text-slate-700 dark:text-slate-200 truncate">{selectedFile.name}</span>
                                    </div>
                                    <button onClick={handleClearFile} className="p-1 rounded-full text-slate-500 hover:bg-slate-200 dark:hover:bg-slate-700 transition-colors flex-shrink-0">
                                        <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}><path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" /></svg>
                                    </button>
                                </div>
                            ) : (
                                <div className="text-center">
                                    <p className="text-sm text-slate-500 dark:text-slate-400 mb-2">Seret & lepas file di sini, atau</p>
                                    <Button type="button" variant="secondary" onClick={handleSelectFileClick}>
                                        Pilih File...
                                    </Button>
                                </div>
                            )}
                        </div>

                        <Button onClick={handleImport} disabled={isParsing || !selectedFile} className="mt-4 w-full flex justify-center items-center gap-2">
                            {isParsing && <Spinner size="small" />}
                            {isParsing ? 'Sedang Mengimpor...' : 'Impor Sekarang'}
                        </Button>

                        {importMessage && (
                           <div className={`mt-4 p-4 rounded-lg flex items-start gap-3 ${importMessage.type === 'success' ? 'bg-emerald-100 text-emerald-800 dark:bg-emerald-900/30 dark:text-emerald-300' : 'bg-red-100 text-red-800 dark:bg-red-900/30 dark:text-red-300'}`}>
                                {importMessage.type === 'success' ? (
                                    <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-emerald-600 dark:text-emerald-400 flex-shrink-0 mt-0.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}><path strokeLinecap="round" strokeLinejoin="round" d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                                ) : (
                                    <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-red-600 dark:text-red-400 flex-shrink-0 mt-0.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}><path strokeLinecap="round" strokeLinejoin="round" d="M10 14l2-2m0 0l2-2m-2 2l-2-2m2 2l2 2m7-2a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                                )}
                                <div className="flex-1">
                                    <h4 className="font-bold text-base mb-1">
                                        {importMessage.type === 'success' ? 'Impor Selesai' : 'Terjadi Kesalahan'}
                                    </h4>
                                    <p className="text-current opacity-90 text-sm">{importMessage.text}</p>
                                </div>
                           </div>
                        )}
                    </div>
                    <div className="bg-white/30 dark:bg-slate-900/50 p-6 rounded-lg text-sm text-slate-700 dark:text-slate-300">
                        <h3 className="text-xl font-semibold text-slate-800 dark:text-white mb-4">Petunjuk Format</h3>
                        <div className="prose prose-sm dark:prose-invert max-w-none">
                            <p><strong>Format Teks:</strong></p>
                            <ul>
                                <li><strong>Excel (.xlsx):</strong> Kolom <code>content</code> diisi teks soal. Kolom <code>mediaType</code> diisi "Teks".</li>
                                <li><strong>Word (.docx):</strong> Tulis soal seperti biasa.</li>
                            </ul>
                             <p><strong>Format Audio/Video:</strong></p>
                            <ul>
                                <li><strong>Excel (.xlsx):</strong> Kolom <code>mediaType</code> diisi "Audio" atau "Video". Kolom <code>content</code> diisi URL media. Kolom <code>promptText</code> diisi teks pengantar.</li>
                                <li><strong>Word (.docx):</strong> Gunakan metadata <code>[MEDIA_TYPE: Video]</code>, <code>[MEDIA_URL: http://...]</code>. Teks soal akan menjadi teks pengantar.</li>
                            </ul>
                        </div>
                    </div>
                </div>
            )}

            {activeTab === 'add' && (
                 <div className="bg-white/30 dark:bg-slate-900/50 p-6 rounded-lg mb-8">
                     <h3 className="text-xl font-semibold text-slate-800 dark:text-white mb-4">Tambah Soal Manual</h3>
                     <div className="space-y-4">
                        <div>
                            <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-2">Tipe Konten</label>
                            <select value={newQuestion.mediaType} onChange={(e) => handleNewQuestionChange('mediaType', e.target.value)} className="w-full md:w-1/3 bg-white/40 dark:bg-slate-800/50 border border-slate-300/80 dark:border-slate-700/80 rounded-lg p-3 focus:ring-2 focus:ring-indigo-500">
                                <option value={QuestionMediaType.TEXT}>Teks</option>
                                <option value={QuestionMediaType.AUDIO}>Audio</option>
                                <option value={QuestionMediaType.VIDEO}>Video</option>
                            </select>
                        </div>

                        {newQuestion.mediaType === QuestionMediaType.TEXT ? (
                             <textarea
                                placeholder="Tulis konten soal di sini..."
                                rows={4}
                                value={newQuestion.content}
                                onChange={(e) => handleNewQuestionChange('content', e.target.value)}
                                className="w-full bg-white/40 dark:bg-slate-800/50 border border-slate-300/80 dark:border-slate-700/80 rounded-lg text-slate-900 dark:text-white placeholder-slate-500 p-3 focus:ring-2 focus:ring-indigo-500"
                            />
                        ) : (
                            <div className='space-y-4'>
                                <Input label="URL Media (Google Drive / YouTube)" value={newQuestion.mediaUrl} onChange={(e) => handleNewQuestionChange('mediaUrl', e.target.value)} placeholder="https://..."/>
                                <textarea
                                    placeholder="Tulis teks pengantar untuk media di sini (misal: 'Perhatikan video berikut untuk menjawab...') "
                                    rows={3}
                                    value={newQuestion.promptText}
                                    onChange={(e) => handleNewQuestionChange('promptText', e.target.value)}
                                    className="w-full bg-white/40 dark:bg-slate-800/50 border border-slate-300/80 dark:border-slate-700/80 rounded-lg text-slate-900 dark:text-white placeholder-slate-500 p-3 focus:ring-2 focus:ring-indigo-500"
                                />
                            </div>
                        )}

                        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                           <Input label="Mata Pelajaran" value={newQuestion.subject} onChange={(e) => handleNewQuestionChange('subject', e.target.value)} />
                           <div>
                                <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-2">Fase</label>
                                <select value={newQuestion.phase} onChange={(e) => handleNewQuestionChange('phase', e.target.value)} className="w-full bg-white/40 dark:bg-slate-800/50 border border-slate-300/80 dark:border-slate-700/80 rounded-lg p-3 focus:ring-2 focus:ring-indigo-500">
                                    <option value="D">Fase D (SMP)</option>
                                    <option value="E">Fase E (SMA)</option>
                                    <option value="F">Fase F (SMA)</option>
                                </select>
                           </div>
                           <div>
                                <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-2">Tipe Soal</label>
                                <select value={newQuestion.type} onChange={(e) => handleNewQuestionChange('type', e.target.value)} className="w-full bg-white/40 dark:bg-slate-800/50 border border-slate-300/80 dark:border-slate-700/80 rounded-lg p-3 focus:ring-2 focus:ring-indigo-500">
                                    <option value={QuestionType.MULTIPLE_CHOICE}>Pilihan Ganda</option>
                                    <option value={QuestionType.ESSAY}>Esai</option>
                                </select>
                           </div>
                        </div>

                        {newQuestion.type === QuestionType.MULTIPLE_CHOICE && (
                            <div className="pt-4 border-t border-white/20 dark:border-slate-700/50">
                                <h4 className="text-lg font-semibold mb-2">Opsi Jawaban</h4>
                                <div className="space-y-3">
                                    {newQuestion.options.map((opt, index) => (
                                        <div key={index} className="flex items-center gap-3">
                                            <input type="radio" name="correctAnswer" checked={newQuestion.correctAnswerIndex === index} onChange={() => handleNewQuestionChange('correctAnswerIndex', index)} className="h-5 w-5 text-indigo-600 focus:ring-indigo-500"/>
                                            <span className="font-semibold text-slate-600 dark:text-slate-300">{String.fromCharCode(65 + index)}.</span>
                                            <Input label="" placeholder={`Teks Opsi ${String.fromCharCode(65 + index)}`} value={opt.text} onChange={(e) => handleOptionChange(index, e.target.value)} className="flex-grow !mb-0"/>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        )}
                        {newQuestion.type === QuestionType.ESSAY && (
                            <div className="pt-4 border-t border-white/20 dark:border-slate-700/50">
                                <h4 className="text-lg font-semibold mb-1">Kunci Jawaban Esai</h4>
                                <p className="text-sm text-slate-600 dark:text-slate-400 mb-3">Masukkan poin-poin kunci atau jawaban ideal. Teks ini akan digunakan sebagai rujukan oleh AI untuk analisis otomatis.</p>
                                <textarea
                                    placeholder="Contoh: Menyebutkan prinsip induksi elektromagnetik, perbandingan jumlah lilitan primer dan sekunder..."
                                    rows={3}
                                    value={newQuestion.essayAnswer}
                                    onChange={(e) => handleNewQuestionChange('essayAnswer', e.target.value)}
                                    className="w-full bg-white/40 dark:bg-slate-800/50 border border-slate-300/80 dark:border-slate-700/80 rounded-lg text-slate-900 dark:text-white placeholder-slate-500 p-3 focus:ring-2 focus:ring-indigo-500"
                                />
                            </div>
                        )}
                        <Button onClick={handleAddQuestion} disabled={isAdding} className="w-full md:w-auto flex justify-center items-center gap-2">
                            {isAdding && <Spinner size="small" />}
                            {isAdding ? "Menyimpan..." : "Simpan Soal"}
                        </Button>
                         {addMessage && <p className={`mt-4 text-sm font-medium p-3 rounded-lg ${addMessage.type === 'success' ? 'bg-emerald-100 text-emerald-800 dark:bg-emerald-900/30 dark:text-emerald-300' : 'bg-red-100 text-red-800 dark:bg-red-900/30 dark:text-red-300'}`}>{addMessage.text}</p>}
                     </div>
                 </div>
            )}

            <div>
                <div className="flex flex-col sm:flex-row justify-between sm:items-center mb-4 gap-4">
                     <h3 className="text-xl font-semibold text-slate-800 dark:text-white">Daftar Soal ({filteredQuestions.length})</h3>
                     <Button onClick={handleExportToCSV} variant="secondary" className="py-2 px-4 text-sm flex items-center gap-2">
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}><path strokeLinecap="round" strokeLinejoin="round" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
                        Ekspor ke CSV
                    </Button>
                </div>

                <div className="bg-white/30 dark:bg-slate-900/50 p-4 rounded-lg mb-4">
                    <div className="grid grid-cols-1 md:grid-cols-4 gap-4 items-end">
                        <div className="md:col-span-2">
                             <Input 
                                label="Cari Soal" 
                                id="search"
                                placeholder="Ketik kata kunci konten..." 
                                value={searchQuery} 
                                onChange={(e) => setSearchQuery(e.target.value)} 
                            />
                        </div>
                        <div>
                            <label htmlFor="subject-filter" className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-2">Mata Pelajaran</label>
                            <select id="subject-filter" value={selectedSubject} onChange={(e) => setSelectedSubject(e.target.value)} className="w-full bg-white/40 dark:bg-slate-800/50 border border-slate-300/80 dark:border-slate-700/80 rounded-lg p-3 focus:ring-2 focus:ring-indigo-500">
                                {uniqueSubjects.map(sub => (
                                    <option key={sub} value={sub}>
                                        {sub === 'all' 
                                            ? `Semua Mapel (${questions.length})` 
                                            : `${sub} (${subjectCounts[sub] || 0})`
                                        }
                                    </option>
                                ))}
                            </select>
                        </div>
                        <div>
                            <label htmlFor="phase-filter" className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-2">Fase</label>
                            <select id="phase-filter" value={selectedPhase} onChange={(e) => setSelectedPhase(e.target.value)} className="w-full bg-white/40 dark:bg-slate-800/50 border border-slate-300/80 dark:border-slate-700/80 rounded-lg p-3 focus:ring-2 focus:ring-indigo-500">
                                <option value="all">Semua Fase</option>
                                <option value="D">Fase D</option>
                                <option value="E">Fase E</option>
                                <option value="F">Fase F</option>
                            </select>
                        </div>
                    </div>
                     <div className='mt-4 flex justify-end'>
                         <Button onClick={handleResetFilters} variant="secondary" className='py-2 px-4 text-sm'>Reset Filter</Button>
                    </div>
                </div>

                <div className="max-h-96 overflow-y-auto bg-white/30 dark:bg-slate-900/50 p-4 rounded-lg">
                    {filteredQuestions.length > 0 ? (
                        <ul className="space-y-3">
                            {filteredQuestions.map((q, index) => (
                                <li key={q.id} className="flex items-center justify-between p-2 bg-white/50 dark:bg-slate-800/60 rounded-md text-sm hover:bg-white/80 dark:hover:bg-slate-800 transition-colors">
                                    <button 
                                        onClick={() => setSelectedQuestionId(q.id)}
                                        className="flex-grow text-left p-2"
                                    >
                                        <strong className="text-indigo-700 dark:text-indigo-400">{filteredQuestions.length - index}. ({q.subject} - {q.phase})</strong>
                                        <p className="mt-1 truncate text-slate-800 dark:text-slate-200">{q.mediaType === QuestionMediaType.TEXT ? q.content : q.promptText}</p>
                                    </button>
                                    <button 
                                        onClick={(e) => { e.stopPropagation(); setEditingQuestionId(q.id); }}
                                        className="ml-4 p-2 rounded-md hover:bg-slate-200 dark:hover:bg-slate-700 transition-colors flex-shrink-0"
                                        title="Edit Soal"
                                    >
                                        <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-slate-600 dark:text-slate-300" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}><path strokeLinecap="round" strokeLinejoin="round" d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" /></svg>
                                    </button>
                                </li>
                            )).reverse()}
                        </ul>
                    ) : (
                        <div className="text-center py-12">
                            <svg xmlns="http://www.w3.org/2000/svg" className="mx-auto h-12 w-12 text-slate-500" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={1.5}><path strokeLinecap="round" strokeLinejoin="round" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
                            <p className="mt-4 text-slate-600 dark:text-slate-400 font-semibold">Tidak ada soal yang cocok</p>
                            <p className="text-sm text-slate-500 dark:text-slate-500">Coba ubah kata kunci atau filter Anda.</p>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
};

export default QuestionBank;

# CBT Kurikulum Merdeka - Sistem Ujian Online

Aplikasi ini adalah sistem ujian online (CBT) komprehensif yang dirancang sesuai standar Kurikulum Merdeka BSKAP terbaru. Dibangun dengan React, Vite, dan Tailwind CSS, aplikasi ini menyediakan antarmuka modern, responsif, dan dapat dihubungkan dengan berbagai jenis backend.

## Fitur Utama

- **Tiga Peran Pengguna**: Siswa, Guru, dan Proktor (Admin) dengan dashboard masing-masing.
- **Registrasi & Login**: Sistem otentikasi berbasis peran dengan pencarian data NISN.
- **Bank Soal Canggih**: Guru dapat menambah soal secara manual atau impor massal dari file `.docx` dan `.xlsx`.
- **Dukungan Soal Multimedia**: Mendukung soal dalam format teks, audio, dan video.
- **Antarmuka Ujian Modern**: Navigasi soal, timer, penanda 'ragu-ragu', dan pengacakan soal.
- **Anti-Cheat**: Deteksi dasar untuk perpindahan tab atau window.
- **Analisis Esai dengan AI**: Guru dapat menganalisis jawaban esai siswa menggunakan Google Gemini API.
- **Desain Estetik**: Latar belakang aurora glass-blur yang dinamis dan nyaman di mata, dengan mode terang/gelap.

---

## Pemasangan & Pengembangan Lokal

Untuk menjalankan aplikasi ini di komputer Anda untuk pengembangan.

**Prasyarat:**
- [Node.js](https://nodejs.org/) (versi 18 atau lebih tinggi)
- [pnpm](https://pnpm.io/installation) (opsional, tapi direkomendasikan untuk manajemen paket)

**Langkah-langkah:**

1.  **Unduh semua file proyek** ke dalam satu folder di komputer Anda.
2.  **Buka terminal** di dalam folder tersebut.
3.  **Install dependensi** dengan menjalankan perintah:
    ```bash
    npm install
    # atau jika menggunakan pnpm
    # pnpm install
    ```
4.  **Jalankan server pengembangan**:
    ```bash
    npm run dev
    # atau
    # pnpm dev
    ```
5.  Buka browser Anda dan navigasi ke `http://localhost:5173` (atau alamat yang ditampilkan di terminal). Aplikasi sekarang berjalan di mode pengembangan.

---

## Metode Deployment 1: Google Apps Script & Google Sheets (Gratis)

Metode ini mengubah Google Sheets menjadi database dan Apps Script menjadi API server Anda.

### Langkah 1: Siapkan Google Sheet sebagai Database

1.  Buat [Google Sheet baru](https://sheets.new).
2.  Buat 4 tab (sheet) di bagian bawah dengan nama persis berikut: `Users`, `Questions`, `NISN_Data`, `Exams`.
3.  Isi baris pertama (header) untuk setiap sheet:
    -   **Sheet `Users`**: `id`, `username`, `fullName`, `role`, `details`
    -   **Sheet `Questions`**: `id`, `type`, `mediaType`, `promptText`, `content`, `options`, `correctAnswer`, `phase`, `subject`
    -   **Sheet `NISN_Data`**: `nisn`, `fullName`, `class`, `school`, `city`, `province`
    -   **Sheet `Exams`**: `id`, `title`, `subject`, `phase`, `durationMinutes`, `questionIds`
4.  Salin ID Spreadsheet dari URL (misalnya: `.../spreadsheets/d/THIS_IS_THE_ID/edit`).

### Langkah 2: Buat Backend di Google Apps Script

1.  Dari Google Sheet Anda, buka `Extensions` > `Apps Script`.
2.  Hapus semua kode di dalam `Code.gs` dan ganti dengan kode backend berikut. **Jangan lupa ganti `ID_SPREADSHEET_ANDA`** dengan ID yang Anda salin tadi.
    ```javascript
    // File: Code.gs
    const SPREADSHEET_ID = "ID_SPREADSHEET_ANDA"; // <--- GANTI INI
    const ss = SpreadsheetApp.openById(SPREADSHEET_ID);
    const usersSheet = ss.getSheetByName("Users");
    const questionsSheet = ss.getSheetByName("Questions");
    const nisnDataSheet = ss.getSheetByName("NISN_Data");
    const examsSheet = ss.getSheetByName("Exams");

    // Fungsi ini akan menyajikan file HTML utama kita
    function doGet(e) {
      return HtmlService.createTemplateFromFile('index').evaluate()
          .setTitle("CBT Kurikulum Merdeka")
          .setXFrameOptionsMode(HtmlService.XFrameOptionsMode.ALLOWALL)
          .addMetaTag('viewport', 'width=device-width, initial-scale=1.0');
    }

    // Fungsi untuk menyertakan file JS/CSS ke dalam HTML
    function include(filename) {
        return HtmlService.createHtmlOutputFromFile(filename).getContent();
    }

    // --- API FUNCTIONS --- //
    // Semua fungsi yang dipanggil dari frontend harus ada di sini

    function fetchNISNData_GS(nisn) {
      const data = nisnDataSheet.getDataRange().getValues();
      for (let i = 1; i < data.length; i++) {
        if (data[i][0].toString() == nisn) {
          return { nisn: data[i][0], fullName: data[i][1], class: data[i][2], school: data[i][3], city: data[i][4], province: data[i][5] };
        }
      }
      return null;
    }

    function registerNewStudent_GS(studentData) {
      const users = usersSheet.getDataRange().getValues();
      for (let i = 1; i < users.length; i++) {
        if (users[i][1] == studentData.nisn) {
          return { user: null, error: 'Pengguna dengan NISN ini sudah terdaftar.' };
        }
      }
      const newId = "user-" + new Date().getTime();
      usersSheet.appendRow([newId, studentData.nisn, studentData.fullName, "Siswa", JSON.stringify(studentData)]);
      return { user: { id: newId, username: studentData.nisn, fullName: studentData.fullName, role: "Siswa", details: studentData }, error: null };
    }

    // ... Implementasikan fungsi API lainnya (login, fetchExams, addQuestion, dll.)
    ```

### Langkah 3: Modifikasi Frontend untuk Memanggil Apps Script

1.  Di proyek lokal Anda, ganti isi file `services/api.ts` dengan kode berikut. Ini akan mengubah pemanggilan data mock menjadi pemanggilan fungsi di `Code.gs`.
    ```typescript
    // File: services/api.ts (versi modifikasi untuk Apps Script)
    import { User, Role, StudentData, Question, Exam } from '../types';

    const gscriptRun = (functionName: string, ...args: any[]): Promise<any> => {
      return new Promise((resolve, reject) => {
        google.script.run
          .withSuccessHandler(resolve)
          .withFailureHandler(reject)
          [functionName](...args);
      });
    };

    // NOTE: Data mock exam dan question tetap ada untuk fallback/demo, 
    // tapi fungsi utama akan memanggil backend.
    export const mockExams: Exam[] = [ /* ...data mock exam... */ ];

    export const fetchNISNData = async (nisn: string): Promise<StudentData | null> => {
        return await gscriptRun('fetchNISNData_GS', nisn);
    };

    export const registerNewStudent = async (studentData: StudentData): Promise<{user: User | null, error?: string}> => {
        return await gscriptRun('registerNewStudent_GS', studentData);
    };

    // ... Implementasikan fungsi lain dengan pola gscriptRun ...
    // Untuk sekarang, kita biarkan fungsi lain menggunakan mock data agar demo tetap berjalan.
    export let mockUsers: User[] = []; // Di Apps Script, data user dikelola di backend
    export const fetchExamDetails = async (examId: string): Promise<{exam: Exam, questions: Question[]}|null> => {
        // Ini tetap mock, perlu fungsi _GS untuk versi production
        const exam = mockExams.find(e => e.id === examId);
        if(!exam) return null;
        // const questions = await gscriptRun('getQuestionsForExam_GS', exam.questionIds);
        return { exam, questions: [] }; // Ganti dengan data real
    };
    // ...
    ```

### Langkah 4: Build Aplikasi & Unggah ke Apps Script

1.  Di terminal komputer lokal Anda, jalankan perintah build:
    ```bash
    npm run build
    ```
    Ini akan membuat folder `dist` berisi file `index.html` dan folder `assets` (dengan file JS dan CSS).

2.  Kembali ke editor Apps Script. Buat file-file baru:
    -   `File` > `New` > `HTML file`. Beri nama `index.html`.
    -   `File` > `New` > `HTML file`. Beri nama `javascript.html`.
    -   `File` > `New` > `HTML file`. Beri nama `stylesheet.html`.

3.  **Unggah Hasil Build:**
    -   Buka file `dist/index.html` di komputer Anda. Salin **SEMUA ISINYA** dan tempel ke `index.html` di Apps Script.
    -   Buka file JavaScript di `dist/assets/` (nama filenya acak, misal `index-abcdef.js`). Salin **SEMUA ISINYA** dan tempel di antara tag `<script>` di `javascript.html`.
        ```html
        <!-- File: javascript.html -->
        <script>
          // PASTE SEMUA KODE JAVASCRIPT DARI FILE HASIL BUILD DI SINI
        </script>
        ```
    -   Buka file CSS di `dist/assets/` (misal `index-123456.css`). Salin **SEMUA ISINYA** dan tempel di antara tag `<style>` di `stylesheet.html`.
        ```html
        <!-- File: stylesheet.html -->
        <style>
          /* PASTE SEMUA KODE CSS DARI FILE HASIL BUILD DI SINI */
        </style>
        ```
4.  **Modifikasi `index.html` di Apps Script** untuk memuat file-file tersebut:
    ```html
    <!DOCTYPE html>
    <html lang="en">
      <head>
        <meta charset="UTF-8" />
        <base target="_top"> <!-- Penting untuk Apps Script -->
        <title>CBT Kurikulum Merdeka</title>
        <?!= include('stylesheet'); ?> <!-- Memuat CSS -->
      </head>
      <body>
        <div id="root"></div>
        <?!= include('javascript'); ?> <!-- Memuat JavaScript -->
      </body>
    </html>
    ```

### Langkah 5: Deploy sebagai Web App

1.  Di editor Apps Script, klik `Deploy` > `New deployment`.
2.  Klik ikon gerigi (⚙️) di sebelah `Select type`, lalu pilih `Web app`.
3.  Isi konfigurasi:
    -   Description: `Versi 1.0`
    -   Execute as: `Me`
    -   Who has access: `Anyone` (agar dapat diakses publik)
4.  Klik `Deploy`. Salin URL Web App yang diberikan. Aplikasi Anda kini live!

---

## Metode Deployment 2: Vercel / Netlify (Modular & Performa Tinggi)

Metode ini menggunakan layanan hosting modern untuk frontend dan backend dapat dibuat terpisah.

### Langkah 1: Siapkan Kode di Git Repository

1.  Pastikan semua file proyek Anda berada di folder lokal.
2.  Buat repository baru di [GitHub](https://github.com/), [GitLab](https://gitlab.com/), atau [Bitbucket](https://bitbucket.org/).
3.  Ikuti instruksi untuk mengunggah (push) kode Anda ke repository tersebut.

### Langkah 2: Deploy Frontend di Vercel

1.  Buat akun di [Vercel](https://vercel.com/) (bisa login dengan akun GitHub).
2.  Di dashboard Vercel, klik `Add New...` > `Project`.
3.  Pilih repository Git yang baru saja Anda buat.
4.  Vercel akan otomatis mendeteksi bahwa ini adalah proyek Vite. Konfigurasi default biasanya sudah benar.
    -   **Build Command**: `vite build` atau `npm run build`
    -   **Output Directory**: `dist`
5.  Klik `Deploy`. Tunggu beberapa saat, dan frontend Anda akan live di URL yang disediakan Vercel.

### Langkah 3: Backend (Pilihan)

Frontend Anda di Vercel masih menggunakan data mock. Untuk membuatnya berfungsi penuh, Anda perlu membuat API backend terpisah.

-   **Pilihan Backend**:
    1.  **Serverless Functions**: Buat fungsi API langsung di Vercel (folder `/api`) atau Netlify Functions.
    2.  **Backend-as-a-Service**: Gunakan [Supabase](https://supabase.com/) atau [Firebase](https://firebase.google.com/) untuk database dan otentikasi.
    3.  **Server Tradisional**: Buat API menggunakan Express.js (Node.js) dan deploy di layanan seperti Render atau Heroku.

-   **Menghubungkan Frontend ke Backend**:
    1.  Setelah backend Anda live dan memiliki URL (misal: `https://api.proyek-cbt.com`), buka pengaturan proyek di Vercel.
    2.  Tambahkan *Environment Variable* baru:
        -   **Name**: `VITE_API_BASE_URL`
        -   **Value**: `https://api.proyek-cbt.com`
    3.  Modifikasi `services/api.ts` di kode Anda untuk menggunakan variabel ini:
        ```typescript
        // services/api.ts
        const API_URL = import.meta.env.VITE_API_BASE_URL;

        export const fetchNISNData = async (nisn: string) => {
            const response = await fetch(`${API_URL}/nisn/${nisn}`);
            return await response.json();
        }
        // ...dan seterusnya untuk semua fungsi API
        ```
    4.  Setiap kali Anda push perubahan ke GitHub, Vercel akan otomatis men-deploy ulang versi terbaru.

